    def download(self, save_dir: Path):
        """Download the dataset."""
        if self.capture_name == "all":
            for capture in self.nerfstudio_dataset:
                self.download_capture(capture, save_dir)
        elif self.capture_name in self.nerfstudio_dataset:
            self.download_capture(self.capture_name, save_dir)
