    def download_capture(self, capture_name: str, save_dir: Path):
        """Download a specific capture."""
        if capture_name in self.nerfstudio_file_ids:
            file_id_or_url = self.nerfstudio_file_ids[capture_name]
            if file_id_or_url.startswith("http"):
                url = file_id_or_url
                download_path = save_dir / f"{capture_name}.zip"
                gdown.download(url, output=str(download_path))
            else:
                url = f"https://drive.google.com/uc?id={file_id_or_url}"
                download_path = save_dir / f"{capture_name}.zip"
                gdown.download(url, output=str(download_path))
            with zipfile.ZipFile(download_path, "r") as zip_ref:
                zip_ref.extractall(str(save_dir))
            if download_path.exists():
                download_path.unlink()
        else:
