        reward = t.info[1]['final_eval_reward']
        if isinstance(reward, torch.Tensor):
            reward = reward.item()
        self._episode_result[env_id].append(reward)
        self.debug(
            "env {} finish episode, final reward: {}, collected episode {}".format(
                env_id, reward, len(self._episode_result[env_id])
            )
        )

self, method: str, path: str, data: Optional[Mapping[str, Any]] = None,
        retries: int = DEFAULT_RETRIES, retry_waiting: float = DEFAULT_RETRY_WAITING
    ) -> requests.Response:
        url = self.get_url(path)
        headers = self._base_headers()
        processed_data = self._data_process(data)
        for i in range(retries):
            try:
                response = self.__session.request(method, url, json=processed_data, headers=headers)
                response.raise_for_status()
                return response
            except Exception as err:
                if i == retries - 1:
                    self._error_handler(err)
                else:
                    time.sleep(retry_waiting)
        raise RuntimeError("Should not reach here")

    def request(
        self, method: str, path: str, data: Optional[Mapping[str, Any]] = None,
        retries: int = DEFAULT_RETRIES, retry_waiting: float = DEFAULT_RETRY_WAITING
    ) -> requests.Response:
        return self.__single_request(method, path, data, retries, retry_waiting)

if mode == 'compute_actor':
            x = self.actor_encoder(inputs)
            x = self.actor_head(x)
            return x
        elif mode == 'compute_critic':
            x = self.critic_encoder(inputs['obs'])
            x = self.critic_head(x)
            return {'q_value': x}
        else:
            raise ValueError("Unrecognized mode: {}".format(mode))

self._update_connection_learner(cur_learners)
        else:
            self._logger.error("Failed to sync with server, message: {}".format(message))
        time.sleep(1)

    def _update_connection_learner(self, cur_learners: list) -> None:
        conn_learners = list(self._learner_connection.keys())
        new_l = set(cur_learners) - set(conn_learners)
        for learner in new_l:
            self._add_learner_connection(learner)
        lost_l = set(conn_learners) - set(cur_learners)
        for learner in lost_l:
            self._remove_learner_connection(learner)

    def _add_learner_connection(self, learner: str) -> None:
        if learner in self._failed_learner_conn:
            self._logger.info("Skip adding failed learner connection: {}".format(learner))
            return
        try:
            self._master.add_slave(learner)
            self._learner_connection[learner] = {'status': 'connected'}
            self._world_size += 1
            self._logger.info("Add learner connection: {}".format(learner))
        except Exception as e:
            self._logger.error("Failed to add learner connection: {}, error: {}".format(learner, e))
            self._failed_learner_conn.add(learner)

    def _remove_learner_connection(self, learner: str) -> None:
        if learner in self._learner_connection:
            self._master.remove_slave(learner)
            del self._learner_connection[learner]
            self._world_size -= 1
            self._logger.info("Remove learner connection: {}".format(learner))
